27	 *    .with("A", () => "It's an A!")
28	 *    .with("B", () => "It's a B!")
29	 *    .exhaustive();
30	 *
31	 */
32	export function match<const input, output = symbols.unset>(
33	  value: input
34	): Match<input, output> {
