32	export const matchPattern = (
33	  pattern: any,
34	  value: any,
35	  select: (key: string, value: unknown) => void
36	): boolean => {
37	  if (isMatcher(pattern)) {
38	    const matcher = pattern[symbols.matcher]();
39	    const { matched, selections } = matcher.match(value);
40	    if (matched && selections) {
41	      Object.keys(selections).forEach((key) => select(key, selections[key]));
42	    }
43	    return matched;
44	  }
45	
46	  if (isObject(pattern)) {
47	    if (!isObject(value)) return false;
48	
49	    // Tuple pattern
50	    if (Array.isArray(pattern)) {
51	      if (!Array.isArray(value)) return false;
52	      let startPatterns = [];
53	      let endPatterns = [];
54	      let variadicPatterns: AnyMatcher[] = [];
55	
56	      for (const i of pattern.keys()) {
57	        const subpattern = pattern[i];
58	        if (isMatcher(subpattern) && subpattern[symbols.isVariadic]) {
59	          variadicPatterns.push(subpattern);
60	        } else if (variadicPatterns.length) {
61	          endPatterns.push(subpattern);
62	        } else {
63	          startPatterns.push(subpattern);
64	        }
65	      }
