74	        if (value.length < startPatterns.length + endPatterns.length) {
75	          return false;
76	        }
77	
78	        const startValues = value.slice(0, startPatterns.length);
79	        const endValues =
80	          endPatterns.length === 0 ? [] : value.slice(-endPatterns.length);
81	        const middleValues = value.slice(
82	          startPatterns.length,
83	          endPatterns.length === 0 ? Infinity : -endPatterns.length
84	        );
85	
86	        return (
87	          startPatterns.every((subPattern, i) =>
88	            matchPattern(subPattern, startValues[i], select)
89	          ) &&
90	          endPatterns.every((subPattern, i) =>
91	            matchPattern(subPattern, endValues[i], select)
92	          ) &&
