    expect(() => {
      const input: 'a' | 'b' = 'c' as any;
      return match(input)
        .with('a', (x) => x)
        .with('b', (x) => x)
        .exhaustive();
    }).toThrow();
  });

  it('should return a value assignable to the explicit output type', () => {
    const input: 'a' | 'b' = 'c' as any;
